import{_ as o,o as e,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"73. Facilities When On Rotation","description":"","frontmatter":{"title":"73. Facilities When On Rotation","eba":"Doctors in Training 2022-2026","topics":["employment","accommodation"]},"headers":[],"relativePath":"ebas/doctors-in-training/accommodation/73-facilities-when-on-rotation.md","filePath":"ebas/doctors-in-training/accommodation/73-facilities-when-on-rotation.md"}'),a={name:"ebas/doctors-in-training/accommodation/73-facilities-when-on-rotation.md"};function r(s,t,p,c,l,h){return e(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="_73-facilities-when-on-rotation" tabindex="-1">73. Facilities When On Rotation <a class="header-anchor" href="#_73-facilities-when-on-rotation" aria-label="Permalink to &quot;73. Facilities When On Rotation&quot;">​</a></h1><p><strong>73.1</strong> Provision of facilities</p><p><strong>(a)</strong> Where a Doctor is permitted or required to live in the residential accommodation provided by the Rotation Hospital, the Rotation Hospital must ensure a safe living environment that includes the following facilities:</p><p><strong>(i)</strong> a separate reasonably furnished bedroom with adequate heating and cooling facilities, including a study desk, chair and study light;</p><p><strong>(ii)</strong> adequate accommodation for study and recreation, which must be available for the Doctor’s exclusive use;</p><p><strong>(iii)</strong> reasonable provision for the preparation of light refreshments by the Doctor;</p><p><strong>(iv)</strong> reasonable provision for the laundering, drying and ironing of personal clothing by the Doctor;</p><p><strong>(v)</strong> adequate well-lit car parking facilities, where possible; and</p><p><strong>(vi)</strong> reliable internet access.</p><p><strong>(b)</strong> Where a Rotation Hospital seeks to acquire or develop new residential accommodation, consideration must be given to the reasonable provision of facilities that allow for the preparation of meals by the Doctor.</p><p><strong>73.2</strong> Safe environment</p><p><strong>(a)</strong> The Rotation Hospital shall assess the residential accommodation following the departure of the previous occupant to ensure that the accommodation is safe.</p><p><strong>(b)</strong> A safety assessment will consider matters including but not limited to:</p><p><strong>(i)</strong> any equipment, appliances and furniture;</p><p><strong>(ii)</strong> hygiene and cleanliness;</p><p><strong>(iii)</strong> security including any security risk arising from isolation and/or shared accommodation; and</p><p><strong>(iv)</strong> ensuring protection from extreme temperatures from external elements.</p><p><strong>73.3</strong> Reporting and Addressing Repairs</p><p><strong>(a)</strong> The Rotation Hospital will provide Doctors who are residing in residential accommodation in writing a document which:</p><p><strong>(i)</strong> facilitates the reporting of repairs, including the reporting of repairs that make the environment unsafe; and</p><p><strong>(ii)</strong> indicates that reported repairs which make the environment unsafe will be assessed expeditiously, with all other repairs assessed within a reasonable timeframe;</p><p><strong>(b)</strong> following its assessment, the property owner will provide to the Doctor a timeframe within which to expect the repairs to be addressed if necessary.</p><p><strong>73.4</strong> Wi-fi</p><p><strong>(a)</strong> The Rotation Hospital will advise the Doctor in writing how to access the wi-fi and the contact details for any necessary technical support; or In the absence of wi-fi, the Rotation Hospital will advise the Doctor prior to their arrival in writing what alternative arrangements for internet access are available.</p><p><strong>73.5</strong> Privacy</p><p>The Rotation Hospital must respect the privacy of a Doctor&#39;s room and, provided there are no exceptional circumstances, representatives of the Rotation Hospital must have entry only with the Doctor&#39;s permission.</p><p><strong>73.6</strong> Routine inspection and maintenance</p><p>The provisions of subclause 73.5 do not apply to the routine maintenance of Doctors&#39; rooms or routine inspections of which notice has been given.</p><p><strong>73.7</strong> Accommodation for Spouse</p><p>A Doctor with a Spouse (as defined in subclause 67.2(g)) and/or a child or children to whom the Doctor is their Primary Carer may request spousal or family quarters if required to be on Rotation to a Rotation Hospital for in excess of six weeks. This entitlement is subject to the availability of spousal or family quarters.</p><p>Plain language terms: rotation accommodation.</p>',31)])])}const m=o(a,[["render",r]]);export{g as __pageData,m as default};
